      u'status':50,
      u'name':u'EGLC',
      u'zoom':9,
      u'coord':{  
         u'lat':51.5053,
         u'lng':0.0553
      },
      u'type':1,
      u'id':5091
   },
   u'last':{  
      u'main':{  
         u'pressure':1025,
         u'temp':285.15,
         u'humidity':76
      },
      u'clouds':[  
         {  
            u'distance':579,
            u'condition':u'SCT'
         },
         {  
            u'distance':1372,
            u'condition':u'BKN'
         }
      ],
      u'visibility':{  
         u'distance':10000,
         u'prefix':1
      },
      u'dt':1482495600,
