It looks like check_error() will throw in these cases, but the compiler doesn't know that.
The fix is to initialize r to NULL in these functions by doing a global replace of "Z3_ast r;" with "Z3_ast r = NULL;", e.g.:

        friend expr operator+(expr const & a, expr const & b) {
            check_context(a, b);
            Z3_ast r = NULL;
            if (a.is_arith() && b.is_arith()) {
                Z3_ast args[2] = { a, b };
                r = Z3_mk_add(a.ctx(), 2, args);
            }
            else if (a.is_bv() && b.is_bv()) {
                r = Z3_mk_bvadd(a.ctx(), a, b);
            }
            else {
                // operator is not supported by given arguments.
                assert(false);
            }
            a.check_error();
            return expr(a.ctx(), r);
        }

